from requests.exceptions import RequestException, Timeout

def safe_get_news(limit: int = 20, timeout: int = 10) -&gt; dict:
    """Fetch news with proper error handling."""
    try:
        response = requests.get(
            f"{BASE_URL}/api/news",
            params={"limit": limit},
            timeout=timeout
        )
        response.raise_for_status()
        return response.json()

    except Timeout:
        print("⚠️ Request timed out. Try again later.")
        return {"articles": [], "error": "timeout"}

    except RequestException as e:
        print(f"❌ Network error: {e}")
        return {"articles": [], "error": str(e)}

    except ValueError as e:
        print(f"❌ Invalid JSON response: {e}")
        return {"articles": [], "error": "invalid_json"}
</code></pre> <pre><code>async function safeGetNews(limit = 20, timeoutMs = 10000) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() =&gt; controller.abort(), timeoutMs);

    try {
        const response = await fetch(
            `${BASE_URL}/api/news?limit=${limit}`,
            { signal: controller.signal }
        );

        clearTimeout(timeoutId);

        if (!response.ok) {
            throw new Error(`HTTP ${response.status}`);
        }

        return await response.json();

    } catch (error) {
        clearTimeout(timeoutId);

        if (error.name === "AbortError") {
            console.warn("⚠️ Request timed out");
            return { articles: [], error: "timeout" };
        }

        console.error(`❌ Error: ${error.message}`);
        return { articles: [], error: error.message };
    }
}
